mapper.select:
SELECT admin_id, admin_pw, last_login_at, create_ts, update_ts
  FROM ADM_LOGIN_INFO
 WHERE admin_id = #{adminId}

SELECT p.post_no, p.board_gbn_cd, p.member_no, p.title, p.view_cnt, p.like_cnt, p.dislike_cnt, p.comment_cnt, p.approval_yn, p.del_yn, p.create_ts, COALESCE(m.nickname, '익명') AS nickname FROM BRD_POST_MST p LEFT JOIN MEM_JOIN_INFO m ON m.member_no = p.member_no WHERE p.del_yn = 'N'
AND p.board_gbn_cd = #{boardGbnCd}
AND p.title LIKE CONCAT('%', #{searchKeyword}, '%')
AND m.nickname LIKE CONCAT('%', #{searchKeyword}, '%')
AND (p.title LIKE CONCAT('%', #{searchKeyword}, '%') OR m.nickname LIKE CONCAT('%', #{searchKeyword}, '%'))
ORDER BY p.post_no DESC LIMIT #{pageSize} OFFSET #{offset}

SELECT member_no, email, nickname, acct_sts_cd, last_login_at, create_ts FROM MEM_JOIN_INFO WHERE 1=1
AND (email LIKE CONCAT('%', #{searchKeyword}, '%') OR nickname LIKE CONCAT('%', #{searchKeyword}, '%'))
ORDER BY member_no DESC LIMIT #{pageSize} OFFSET #{offset}
